  CloseIcon,
  EditIcon,
  RefreshIcon,
  SaveIcon,
  Screen,
  ScreenHeader,
  Splitter,
  ToolGroup,
  useAxiosFactory,
  useMessageAnnouncer,
} from "@textile/common";
import {
  Box,
  IconButton,
  IconButtonProps,
  Stack,
  SxProps,
  Tab,
  Tabs,
  TextField,
  TextFieldProps,
  Tooltip,
} from "@textile/mui";
import {
  ChangeEvent,
  FunctionComponent,
  SyntheticEvent,
  useCallback,
  useEffect,
  useMemo,
  useState,
} from "react";

import { DataDictionaryFieldFormDialog } from "./data-dictionary-field-form-dialog.component";
import { DataDictionaryFieldPortfoliosPanel } from "./data-dictionary-field-portfolios-panel.component";
import {
  DataDictionaryFieldPropertiesPanel,
  getDataDictionaryFieldSummaryRows,
} from "./data-dictionary-field-properties-panel.component";
import { DataDictionaryFieldUsagePanel } from "./data-dictionary-field-usage-panel.component";
import { DataDictionaryField } from "./data-dictionary.types";
import { ReplaceFieldButton } from "./replace-data-dictionary-field-usage.component";
import { baseUrl } from "../../apis";
import { GetQuickFilterTextParams } from "@textile/ag-grid";

