  display: "flex",
  flexDirection: "column",
};
const filterControlSx: SxProps = {
  flex: "1 1 0px",
  maxWidth: "512px"
};
const filterControlSpacerSx: SxProps = {
  flex: "1 1 0px",
};
const dataDictionaryScreenContentContainerSx: SxProps = {
  flex: "1 1 0px",
};
const dataDictionaryFieldsGridSx: SxProps = {
  flex: "2 2 0px",
  height: "100%",
};
const dataDictionaryDetailsContainerSx: SxProps = {
  flex: "1 1 0px",
  flexGrow: 1,
  flexDirection: "column",
  backgroundColor: "rgb(240, 240, 240)",
  paddingLeft: "12px",
  paddingRight: "12px",
  paddingTop: "0px",
  borderRadius: "5px 5px 5px 0",
};
const dataDictionaryDetailPanelSx: SxProps = {
  flex: "1 1 0px",
  overflow: "auto",
  mb: "12px",
  boxShadow: "0px 0px 4px 0px rgba(0, 0, 0, 0.25)",
};
const dataDictionaryPortfolioPanelSx: SxProps = {
  flex: "1 1 0px",
  overflow: "auto",
};
const dataDictionaryUsagePanelSx: SxProps = {
  flex: "1 1 0px",
  overflow: "auto",
};
const shimBoxSx: SxProps = {
  flexGrow: 1,
};

const toolGroupIconSx: SxProps = { height: "34px", width: "34px" };
const searchTextFieldSx: SxProps = {
  flexGrow: 1,
  maxWidth: "100px",
  width: "88px",
  mr: "6px",
  "& .MuiInputBase-root": {
    paddingY: 0,
    height: "32px",
  },
  "& .MuiInputLabel-root": {
    fontSize: "14px",
  },
};

const aggregationLevelFilterTextFieldProps: TextFieldProps = {
  label: "Aggregation Level",
  variant: "outlined",
};
const fieldTypeFilterTextFieldProps: TextFieldProps = {
  label: "Field Type",
  variant: "outlined",
};

enum DetailsTabs {
  Portfolios = "portfolios",
  Properties = "properties",
  Usage = "usage",
}

const dataDictionarFieldsDeleteOperation: FabricAsyncOperation = {
  method: "post",
  url: `${baseUrl}/dataDictionaryFields:batchDelete`,
  operationConfirmedParamLocation: "body",
  idsField: "names",
};

export const DataDictionaryScreen: FunctionComponent = () => {
  const [aggregationLevelFilter, setAggregationLevelFilter] =
    useState<string>("");
  const [fieldTypeFilter, setFieldTypeFilter] = useState<string>("");
