  const [fieldUsageSearchFilter, setFieldUsageSearchFilter] =
    useState<string>("");
  const [selectedRows, setSelectedRows] = useState<DataDictionaryField[]>([]);
  const [isSytemType, setIsSytemType] = useState<boolean>(false);

  const [isLoading, setIsLoading] = useState(false);
  const messageAnnouncer = useMessageAnnouncer();

  const iconButtonProps = useMemo<IconButtonProps>(() => {
    const anySystemSelected = selectedRows.some((row) => row.type === "SYS");
    return fieldTypeFilter === "SYS" || anySystemSelected
      ? { disabled: true }
      : {};
  }, [fieldTypeFilter, selectedRows]);

  const { createAxiosInstance } = useAxiosFactory();
  const [dataDictionaryFieldGridRefreshToken, refreshDataDictionaryFieldGrid] =
    useRefreshToken();
  const [dataDictionaryFieldRefreshToken, refreshDataDictionaryField] =
