  const [
    dataDictionaryFieldUsageRefreshToken,
    refreshDataDictionaryFieldUsage,
  ] = useRefreshToken();

  const handleAggregationLevelFilterChange = (
    event: SyntheticEvent,
    value: unknown
  ) => {
    setAggregationLevelFilter((value as LookupItem).code);
  };

