    async (data: LookupItem[]) => {
      const allAggregationLevelOption: LookupItemOption = {
        code: "",
        description: "All",
      };
      return [allAggregationLevelOption, ...data];
    },
    []
  );

  const handleFieldTypeFilterChange = (
    event: SyntheticEvent,
    value: unknown
  ) => {
    setFieldTypeFilter((value as LookupItem).code);
  };

  const handlePopulateFieldTypeFilterOptions = useCallback(
    async (data: LookupItem[]) => {
      const allFieldTypeOption: LookupItemOption = {
        code: "",
        description: "All",
      };
      return [allFieldTypeOption, ...data];
    },
    []
  );

  const handleDataDictionaryFieldSelectionChange = (
    selections: DataDictionaryField[]
  ) => {
    setSelectedRows(selections);
    if (selections.length === 1) {
      const [selectedDataDictionaryField] = selections;
      const isSystem = selectedDataDictionaryField?.type
        ? selectedDataDictionaryField.type === "SYS"
        : false;
      const isPortfolioScope =
        selectedDataDictionaryField?.scope == "D" ||
        selectedDataDictionaryField?.scope == "GD";
      setEnablePortfolioTab(isPortfolioScope && !isSystem); //enable portfolio tab only for Portfolio and Global, Portfolio Level Override scope
      if (
        isSystem ||
        (!isPortfolioScope && currentTab == DetailsTabs.Portfolios)
      )
        setCurrentTab(DetailsTabs.Properties);

      setSelectedDataDictionaryFieldId(selectedDataDictionaryField?.id ?? null);
      setIsSytemType(isSystem);
    } else {
      setSelectedDataDictionaryFieldId(null);
      setDataDictionaryField(null);
      setIsSytemType(false);
    }
    setPortfolioEditMode(false);
  };

  const handleDetailsTabChange = (
    event: SyntheticEvent,
    value: DetailsTabs
  ) => {
    setCurrentTab(value);
  };

  const handlePortfoliosEditClick = () => {
    setPortfolioEditMode(true);
  };

  const handlePortfoliosSelection = (portfolios: string[]) => {
    setSelectedPortfolios(portfolios);
  };

  const handlePortfoliosSaveClick = async () => {
    try {
      const axios = await createAxiosInstance();
      setIsLoading(true);
      await axios.post(
        `${baseUrl}/dataDictionaryFields/${dataDictionaryField?.field_name}/fieldPortfolios:batchMerge?operation_confirmed=1`,
        {
          portfolio_ids: selectedPortfolios,
        }
      );
      setPortfolioEditMode(false);
      setPortfoliosSearchFilter("");
      refreshDataDictionaryField();
    } catch (error) {
      messageAnnouncer.error(`Failed to Save: ${error}`);
    } finally {
      setIsLoading(false);
    }
  };

  const handlePortfoliosCancleClick = async () => {
    setPortfolioEditMode(false);
  };

  const handlePortfoliosSearchFilterChange = (
    event: ChangeEvent<HTMLInputElement>
  ) => {
    setPortfoliosSearchFilter(event.target.value);
  };

  const handleRefreshFieldUsage = () => {
    refreshDataDictionaryFieldUsage();
  };

  const handleFieldUsageSearchFilterChange = (
    event: ChangeEvent<HTMLInputElement>
  ) => {
    setFieldUsageSearchFilter(event.target.value);
  };

  const handleReplaceComplete = () => {
