import {
  DataGridActionViewSource,
  DownloadActionMenu,
  LookupAutocomplete,
  LookupItem,
  LookupItemOption,
  SummaryDownloadActionMenu,
  ViewCustomSourceActionDialog,
} from "@solvasam/bizcomponents";
import {
  AsyncDataGridPanel,
  DataGridActionAdd,
  DataGridActionDelete,
  DataGridActionEdit,
  FabricAsyncOperation,
  DataGridDataServiceSource,
  DataGridQuickSearch,
  useRefreshToken,
  ActionMenu,
  DataGridActionRefresh,
} from "@textile/biz-components";
import {
  CloseIcon,
  EditIcon,
  RefreshIcon,
  SaveIcon,
  Screen,
  ScreenHeader,
  Splitter,
  ToolGroup,
  useAxiosFactory,
  useMessageAnnouncer,
} from "@textile/common";
import {
  Box,
  IconButton,
  IconButtonProps,
  Stack,
  SxProps,
  Tab,
  Tabs,
  TextField,
  TextFieldProps,
  Tooltip,
} from "@textile/mui";
import {
  ChangeEvent,
  FunctionComponent,
  SyntheticEvent,
  useCallback,
  useEffect,
  useMemo,
  useState,
} from "react";

import { DataDictionaryFieldFormDialog } from "./data-dictionary-field-form-dialog.component";
import { DataDictionaryFieldPortfoliosPanel } from "./data-dictionary-field-portfolios-panel.component";
import {
  DataDictionaryFieldPropertiesPanel,
  getDataDictionaryFieldSummaryRows,
} from "./data-dictionary-field-properties-panel.component";
import { DataDictionaryFieldUsagePanel } from "./data-dictionary-field-usage-panel.component";
import { DataDictionaryField } from "./data-dictionary.types";
import { ReplaceFieldButton } from "./replace-data-dictionary-field-usage.component";
import { baseUrl } from "../../apis";
import { GetQuickFilterTextParams } from "@textile/ag-grid";

const screenSx: SxProps = {
  display: "flex",
  flexDirection: "column",
};
const filterControlSx: SxProps = {
  flex: "1 1 0px",
  maxWidth: 512,
};
const filterControlSpacerSx: SxProps = {
  flex: "1 1 0px",
};
const dataDictionaryScreenContentContainerSx: SxProps = {
  flex: "1 1 0px",
};
const dataDictionaryFieldsGridSx: SxProps = {
  flex: "2 2 0px",
  height: "100%",
};
const dataDictionaryDetailsContainerSx: SxProps = {
  flex: "1 1 0px",
  flexGrow: 1,
  flexDirection: "column",
  backgroundColor: "rgb(240, 240, 240)",
  paddingLeft: "12px",
  paddingRight: "12px",
  paddingTop: "0px",
  borderRadius: "5px 5px 5px 0",
};
const dataDictionaryDetailPanelSx: SxProps = {
  flex: "1 1 0px",
  overflow: "auto",
  mb: "12px",
  boxShadow: "0px 0px 4px 0px rgba(0, 0, 0, 0.25)",
};
const dataDictionaryPortfolioPanelSx: SxProps = {
  flex: "1 1 0px",
  overflow: "auto",
};
const dataDictionaryUsagePanelSx: SxProps = {
  flex: "1 1 0px",
  overflow: "auto",
};
const shimBoxSx: SxProps = {
  flexGrow: 1,
};

const toolGroupIconSx: SxProps = { height: "24px", width: "24px" };
const searchTextFieldSx: SxProps = {
  flexGrow: 1,
  maxWidth: "100px",
  width: "116px",
  mr: "6px",
  // border: "1px solid #D9D9D9",
  "& .MuiInputBase-root": {
    paddingY: 0,
    height: "28px",
    backgroundColor: "#F0F0F0",
  },
  "& .MuiInputLabel-root": {
    fontSize: "12px",
  },
};

const aggregationLevelFilterTextFieldProps: TextFieldProps = {
  label: "Aggregation Level",
  variant: "outlined",
};
const fieldTypeFilterTextFieldProps: TextFieldProps = {
  label: "Field Type",
  variant: "outlined",
};

enum DetailsTabs {
  Portfolios = "portfolios",
  Properties = "properties",
  Usage = "usage",
}

const dataDictionarFieldsDeleteOperation: FabricAsyncOperation = {
  method: "post",
  url: `${baseUrl}/dataDictionaryFields:batchDelete`,
  operationConfirmedParamLocation: "body",
  idsField: "names",
};

export const DataDictionaryScreen: FunctionComponent = () => {
  const [aggregationLevelFilter, setAggregationLevelFilter] =
    useState<string>("");
  const [fieldTypeFilter, setFieldTypeFilter] = useState<string>("");
  const [selectedDataDictionaryFieldId, setSelectedDataDictionaryFieldId] =
    useState<string | null>(null);
  const [currentTab, setCurrentTab] = useState<DetailsTabs>(
    DetailsTabs.Properties
  );
  const [dataDictionaryField, setDataDictionaryField] =
    useState<DataDictionaryField | null>(null);
  const [portfolioEditMode, setPortfolioEditMode] = useState<boolean>(false);
  const [enablePortfolioTab, setEnablePortfolioTab] = useState<boolean>(true);
  const [selectedPortfolios, setSelectedPortfolios] = useState<string[]>([]);
  const [portfoliosSearchFilter, setPortfoliosSearchFilter] =
    useState<string>("");
  const [fieldUsageSearchFilter, setFieldUsageSearchFilter] =
    useState<string>("");
  const [selectedRows, setSelectedRows] = useState<DataDictionaryField[]>([]);
  const [isSytemType, setIsSytemType] = useState<boolean>(false);

  const [isLoading, setIsLoading] = useState(false);
  const messageAnnouncer = useMessageAnnouncer();

  const iconButtonProps = useMemo<IconButtonProps>(() => {
    const anySystemSelected = selectedRows.some((row) => row.type === "SYS");
    return fieldTypeFilter === "SYS" || anySystemSelected
      ? { disabled: true }
      : {};
  }, [fieldTypeFilter, selectedRows]);

  const { createAxiosInstance } = useAxiosFactory();
  const [dataDictionaryFieldGridRefreshToken, refreshDataDictionaryFieldGrid] =
    useRefreshToken();
  const [dataDictionaryFieldRefreshToken, refreshDataDictionaryField] =
    useRefreshToken();
  const [
    dataDictionaryFieldUsageRefreshToken,
    refreshDataDictionaryFieldUsage,
  ] = useRefreshToken();

  const handleAggregationLevelFilterChange = (
    event: SyntheticEvent,
    value: unknown
  ) => {
    setAggregationLevelFilter((value as LookupItem).code);
  };

  const handlePopulateAggregationLevelFilterOptions = useCallback(
    async (data: LookupItem[]) => {
      const allAggregationLevelOption: LookupItemOption = {
        code: "",
        description: "All",
      };
      return [allAggregationLevelOption, ...data];
    },
    []
  );

  const handleFieldTypeFilterChange = (
    event: SyntheticEvent,
    value: unknown
  ) => {
    setFieldTypeFilter((value as LookupItem).code);
  };

  const handlePopulateFieldTypeFilterOptions = useCallback(
    async (data: LookupItem[]) => {
      const allFieldTypeOption: LookupItemOption = {
        code: "",
        description: "All",
      };
      return [allFieldTypeOption, ...data];
    },
    []
  );

  const handleDataDictionaryFieldSelectionChange = (
    selections: DataDictionaryField[]
  ) => {
    setSelectedRows(selections);
    if (selections.length === 1) {
      const [selectedDataDictionaryField] = selections;
      const isSystem = selectedDataDictionaryField?.type
        ? selectedDataDictionaryField.type === "SYS"
        : false;
      const isPortfolioScope =
        selectedDataDictionaryField?.scope == "D" ||
        selectedDataDictionaryField?.scope == "GD";
      setEnablePortfolioTab(isPortfolioScope && !isSystem); //enable portfolio tab only for Portfolio and Global, Portfolio Level Override scope
      if (
        isSystem ||
        (!isPortfolioScope && currentTab == DetailsTabs.Portfolios)
      )
        setCurrentTab(DetailsTabs.Properties);

      setSelectedDataDictionaryFieldId(selectedDataDictionaryField?.id ?? null);
      setIsSytemType(isSystem);
    } else {
      setSelectedDataDictionaryFieldId(null);
      setDataDictionaryField(null);
      setIsSytemType(false);
    }
    setPortfolioEditMode(false);
  };

  const handleDetailsTabChange = (
    event: SyntheticEvent,
    value: DetailsTabs
  ) => {
    setCurrentTab(value);
  };

  const handlePortfoliosEditClick = () => {
    setPortfolioEditMode(true);
  };

  const handlePortfoliosSelection = (portfolios: string[]) => {
    setSelectedPortfolios(portfolios);
  };

  const handlePortfoliosSaveClick = async () => {
    try {
      const axios = await createAxiosInstance();
      setIsLoading(true);
      await axios.post(
        `${baseUrl}/dataDictionaryFields/${dataDictionaryField?.field_name}/fieldPortfolios:batchMerge?operation_confirmed=1`,
        {
          portfolio_ids: selectedPortfolios,
        }
      );
      setPortfolioEditMode(false);
      setPortfoliosSearchFilter("");
      refreshDataDictionaryField();
    } catch (error) {
      messageAnnouncer.error(`Failed to Save: ${error}`);
    } finally {
      setIsLoading(false);
    }
  };

  const handlePortfoliosCancleClick = async () => {
    setPortfolioEditMode(false);
  };

  const handlePortfoliosSearchFilterChange = (
    event: ChangeEvent<HTMLInputElement>
  ) => {
    setPortfoliosSearchFilter(event.target.value);
  };

  const handleRefreshFieldUsage = () => {
    refreshDataDictionaryFieldUsage();
  };

  const handleFieldUsageSearchFilterChange = (
    event: ChangeEvent<HTMLInputElement>
  ) => {
    setFieldUsageSearchFilter(event.target.value);
  };

  const handleReplaceComplete = () => {
    refreshDataDictionaryFieldGrid();
  };

  const dataDictionaryGridDataSource = useMemo<DataGridDataServiceSource>(
    () => ({
      url: `${baseUrl}/dataDictionaryFields:view`,
      queryParams: {
        ...((aggregationLevelFilter || fieldTypeFilter) && {
          "paging.filter":
            (aggregationLevelFilter
              ? `aggregation_level="${aggregationLevelFilter}"`
              : "") +
            (aggregationLevelFilter && fieldTypeFilter ? " AND " : "") +
            (fieldTypeFilter ? `type="${fieldTypeFilter}"` : ""),
        }),
      },
    }),
    [aggregationLevelFilter, fieldTypeFilter]
  );

  const urlToLoadDataDictionaryField = `${baseUrl}/dataDictionaryFields/${selectedDataDictionaryFieldId}`;
  useEffect(() => {
    const abortController = new AbortController();
    const loadDataDictionaryField = async (
      abortController: AbortController
    ) => {
      try {
        const axios = await createAxiosInstance();
        const { data } = await axios.get<DataDictionaryField>(
          urlToLoadDataDictionaryField,
          { signal: abortController.signal }
        );
        setDataDictionaryField(data);
      } catch (error) {
        if (abortController.signal.aborted) {
          return;
        }
        messageAnnouncer.error(`Failed: ${error}`);
      }
    };
    if (selectedDataDictionaryFieldId) {
      loadDataDictionaryField(abortController);
    } else {
      setDataDictionaryField(null);
    }

    return () => {
      abortController.abort();
    };
  }, [
    createAxiosInstance,
    dataDictionaryFieldRefreshToken,
    messageAnnouncer,
    selectedDataDictionaryFieldId,
    urlToLoadDataDictionaryField,
  ]);

  const RenderTabIcons = () =>
    dataDictionaryField ? (
      currentTab === DetailsTabs.Portfolios ? (
        <>
          <TextField
            value={portfoliosSearchFilter}
            onChange={handlePortfoliosSearchFilterChange}
            label="Search"
            type="search"
            variant="outlined"
            // InputProps={{
            //   endAdornment: (
            //     <InputAdornment position="end">
            //       <MatchCaseIcon />
            //       <MatchWordIcon />
            //       <RegularExpressionIcon/>
            //       {/* <RegexIcon /> */}
            //     </InputAdornment>
            //   ),
            // }}
            sx={searchTextFieldSx}
          ></TextField>
          {portfolioEditMode ? (
            <>
              <Tooltip title="Save">
                <span>
                  <IconButton
                    sx={toolGroupIconSx}
                    onClick={handlePortfoliosSaveClick}
                    aria-label="Save"
                    disabled={selectedPortfolios.length === 0 || isLoading}
                  >
                    <SaveIcon size={24}></SaveIcon>
                  </IconButton>
                </span>
              </Tooltip>
              <Tooltip title="Cancel">
                <span>
                  <IconButton
                    sx={toolGroupIconSx}
                    onClick={handlePortfoliosCancleClick}
                    aria-label="Cancel"
                    disabled={isLoading}
                  >
                    <CloseIcon size={24}></CloseIcon>
                  </IconButton>
                </span>
              </Tooltip>
            </>
          ) : (
            <Tooltip title="Edit">
              <IconButton
                sx={toolGroupIconSx}
                onClick={handlePortfoliosEditClick}
                aria-label="Edit"
              >
                <EditIcon size={24}></EditIcon>
              </IconButton>
            </Tooltip>
          )}
        </>
      ) : currentTab === DetailsTabs.Usage ? (
        <>
          <TextField
            value={fieldUsageSearchFilter}
            onChange={handleFieldUsageSearchFilterChange}
            label="Search"
            type="search"
            variant="outlined"
            sx={searchTextFieldSx}
          ></TextField>
          <ReplaceFieldButton
            fieldName={dataDictionaryField.field_name}
            onReplaceComplete={handleReplaceComplete}
          ></ReplaceFieldButton>
          <Tooltip title="Refresh">
            <IconButton
              sx={toolGroupIconSx}
              onClick={handleRefreshFieldUsage}
              aria-label="Refresh"
            >
              <RefreshIcon size={24}></RefreshIcon>
            </IconButton>
          </Tooltip>
        </>
      ) : currentTab === DetailsTabs.Properties ? (
        <SummaryDownloadActionMenu
          filename={"Data Dictionary Field"}
          rows={getDataDictionaryFieldSummaryRows(dataDictionaryField)}
        />
      ) : null
    ) : null;

  return (
    <Screen navigationId="solvasam-domaindata-ui-data-dictionary" sx={screenSx}>
      <ScreenHeader></ScreenHeader>
      <Stack spacing={2.25} direction="row" marginBottom={1}>
        <LookupAutocomplete
          lookupType="AGGREGATION_LEVEL"
          value={aggregationLevelFilter}
          onChange={handleAggregationLevelFilterChange}
          onBeforePopulate={handlePopulateAggregationLevelFilterOptions}
          textFieldProps={aggregationLevelFilterTextFieldProps}
          sx={filterControlSx}
          disableClearable
        ></LookupAutocomplete>
        <LookupAutocomplete
          lookupType="LOOKUP_FIELD_TYPE"
          value={fieldTypeFilter}
          onChange={handleFieldTypeFilterChange}
          onBeforePopulate={handlePopulateFieldTypeFilterOptions}
          textFieldProps={fieldTypeFilterTextFieldProps}
          sx={filterControlSx}
          disableClearable
        ></LookupAutocomplete>
        <Box sx={filterControlSpacerSx}></Box>
      </Stack>
      <Stack direction="row" sx={dataDictionaryScreenContentContainerSx}>
        <Splitter expandable={true}>
          <AsyncDataGridPanel
            dataSource={dataDictionaryGridDataSource}
            onSelectionChanged={handleDataDictionaryFieldSelectionChange}
            refreshToken={dataDictionaryFieldGridRefreshToken}
            sx={dataDictionaryFieldsGridSx}
            gridPersistOptions={{
              key: `dd-data-dict`,
              enabled: true,
            }}
            rowSelectionMode="multi"
            agGridProps={{
              defaultColDef: {
                getQuickFilterText: (
                  // eslint-disable-next-line @typescript-eslint/no-explicit-any
                  params: GetQuickFilterTextParams<any, any>
                ) => {
                  return params.column.getColId() == "display_name"
                    ? params.value
                    : "";
                },
              },
              quickFilterMatcher: (
                quickFilterParts: string[],
                rowQuickFilterAggregateText: string
              ) => {
                return (
                  rowQuickFilterAggregateText.indexOf(
                    quickFilterParts.join(" ")
                  ) >= 0
                );
              },
            }}
          >
            <DataGridQuickSearch
            // sx={{ width: "1.75rem" }}
            // label="Search by Field Name"
            ></DataGridQuickSearch>
            <DataGridActionAdd
              dialog={
                <DataDictionaryFieldFormDialog
                  selected_aggregation_level={
                    aggregationLevelFilter ? aggregationLevelFilter : "ISSU"
                  }
                ></DataDictionaryFieldFormDialog>
              }
              iconTooltipTitle="Add User-Defined Field"
              onUpdateUi={(gridMeta, agGridApi) => {
                setCurrentTab(DetailsTabs.Properties);
                const selectedNodes = agGridApi.getSelectedNodes();

                if (selectedNodes && selectedNodes[0]) {
                  const selectedNode = selectedNodes[0];

                  if (selectedNode.rowIndex) {
                    agGridApi.ensureIndexVisible(selectedNode.rowIndex);
                  }
                }
              }}
            ></DataGridActionAdd>
            <DataGridActionEdit
              dialog={
                <DataDictionaryFieldFormDialog></DataDictionaryFieldFormDialog>
              }
              onUpdateUi={refreshDataDictionaryField}
            ></DataGridActionEdit>
            <DataGridActionDelete
              operation={dataDictionarFieldsDeleteOperation}
              iconButtonProps={iconButtonProps}
              rowSelectionMode="multi"
            ></DataGridActionDelete>
            <DownloadActionMenu />
            <ActionMenu>
              <DataGridActionRefresh type="menuitem" icon={null} />
              <DataGridActionViewSource
                type="menuitem"
                datasource={dataDictionaryGridDataSource}
              ></DataGridActionViewSource>
            </ActionMenu>
          </AsyncDataGridPanel>
          {dataDictionaryField ? (
            <Stack sx={dataDictionaryDetailsContainerSx}>
              <ToolGroup
                sx={{
                  pt: "8px",
                  height: "40px",
                  mb: "4px",
                  alignItems: "center",
                  gap: "6px",
                }}
                aria-label={
                  currentTab === DetailsTabs.Portfolios
                    ? "Portfolios"
                    : currentTab === DetailsTabs.Usage
                    ? "Field Usage"
                    : ""
                }
              >
                <Tabs
                  value={currentTab}
                  onChange={handleDetailsTabChange}
                  sx={{ 
                    flex: 1,
                    '& .MuiTabs-indicator': {
                      display: 'none'
                    },
                    borderBottom: '1px solid #D9D9D9'
                  }}
                >
                  <Tab label="Properties" value={DetailsTabs.Properties}></Tab>
                  {enablePortfolioTab ? (
                    <Tab
                      label="Portfolios"
                      value={DetailsTabs.Portfolios}
                    ></Tab>
                  ) : null}

                  {!isSytemType ? (
                    <Tab label="Field Usage" value={DetailsTabs.Usage}></Tab>
                  ) : null}
                </Tabs>
                <Box sx={shimBoxSx}></Box>
                <RenderTabIcons />
                <ViewCustomSourceActionDialog
                  url={urlToLoadDataDictionaryField}
                />
              </ToolGroup>
              {currentTab === DetailsTabs.Properties ? (
                <DataDictionaryFieldPropertiesPanel
                  dataDictionaryField={dataDictionaryField}
                  sx={dataDictionaryDetailPanelSx}
                ></DataDictionaryFieldPropertiesPanel>
              ) : null}
              {currentTab === DetailsTabs.Portfolios ? (
                <DataDictionaryFieldPortfoliosPanel
                  portfolioList={dataDictionaryField.portfolio_ids}
                  editMode={portfolioEditMode}
                  onSelectionChanged={handlePortfoliosSelection}
                  searchFilter={portfoliosSearchFilter}
                  sx={dataDictionaryPortfolioPanelSx}
                  isLoading={isLoading}
                ></DataDictionaryFieldPortfoliosPanel>
              ) : null}
              {currentTab === DetailsTabs.Usage ? (
                <DataDictionaryFieldUsagePanel
                  fieldName={dataDictionaryField.field_name}
                  refreshToken={dataDictionaryFieldUsageRefreshToken}
                  searchFilter={fieldUsageSearchFilter}
                  sx={dataDictionaryUsagePanelSx}
                ></DataDictionaryFieldUsagePanel>
              ) : null}
            </Stack>
          ) : null}
        </Splitter>
      </Stack>
    </Screen>
  );
};

