            //   endAdornment: (
            //     <InputAdornment position="end">
            //       <MatchCaseIcon />
            //       <MatchWordIcon />
            //       <RegularExpressionIcon/>
            //       {/* <RegexIcon /> */}
            //     </InputAdornment>
            //   ),
            // }}
            sx={searchTextFieldSx}
          ></TextField>
