              <Tooltip title="Cancel">
                <span>
                  <IconButton
                    sx={toolGroupIconSx}
                    onClick={handlePortfoliosCancleClick}
                    aria-label="Cancel"
                    disabled={isLoading}
                  >
                    <CloseIcon size={24}></CloseIcon>
                  </IconButton>
                </span>
              </Tooltip>
            </>
          ) : (
            <Tooltip title="Edit">
              <IconButton
                sx={toolGroupIconSx}
                onClick={handlePortfoliosEditClick}
                aria-label="Edit"
              >
                <EditIcon size={24}></EditIcon>
              </IconButton>
            </Tooltip>
          )}
        </>
      ) : currentTab === DetailsTabs.Usage ? (
        <>
          <TextField
            value={fieldUsageSearchFilter}
            onChange={handleFieldUsageSearchFilterChange}
            label="Search"
            type="search"
            variant="outlined"
            sx={searchTextFieldSx}
          ></TextField>
          <ReplaceFieldButton
            fieldName={dataDictionaryField.field_name}
            onReplaceComplete={handleReplaceComplete}
          ></ReplaceFieldButton>
          <Tooltip title="Refresh">
            <IconButton
              sx={toolGroupIconSx}
              onClick={handleRefreshFieldUsage}
              aria-label="Refresh"
            >
              <RefreshIcon size={24}></RefreshIcon>
            </IconButton>
          </Tooltip>
        </>
      ) : currentTab === DetailsTabs.Properties ? (
        <SummaryDownloadActionMenu
          filename={"Data Dictionary Field"}
          rows={getDataDictionaryFieldSummaryRows(dataDictionaryField)}
        />
      ) : null
    ) : null;

  return (
    <Screen navigationId="solvasam-domaindata-ui-data-dictionary" sx={screenSx}>
      <ScreenHeader></ScreenHeader>
      <Stack spacing={2.25} direction="row" marginBottom={1}>
        <LookupAutocomplete
          lookupType="AGGREGATION_LEVEL"
          value={aggregationLevelFilter}
          onChange={handleAggregationLevelFilterChange}
          onBeforePopulate={handlePopulateAggregationLevelFilterOptions}
          textFieldProps={aggregationLevelFilterTextFieldProps}
          sx={filterControlSx}
          disableClearable
        ></LookupAutocomplete>
        <LookupAutocomplete
          lookupType="LOOKUP_FIELD_TYPE"
          value={fieldTypeFilter}
          onChange={handleFieldTypeFilterChange}
          onBeforePopulate={handlePopulateFieldTypeFilterOptions}
          textFieldProps={fieldTypeFilterTextFieldProps}
          sx={filterControlSx}
          disableClearable
        ></LookupAutocomplete>
        <Box sx={filterControlSpacerSx}></Box>
      </Stack>
      <Stack direction="row" sx={dataDictionaryScreenContentContainerSx}>
        <Splitter expandable={true}>
          <AsyncDataGridPanel
            dataSource={dataDictionaryGridDataSource}
            onSelectionChanged={handleDataDictionaryFieldSelectionChange}
            refreshToken={dataDictionaryFieldGridRefreshToken}
            sx={dataDictionaryFieldsGridSx}
            gridPersistOptions={{
              key: `dd-data-dict`,
              enabled: true,
            }}
            rowSelectionMode="multi"
            agGridProps={{
              defaultColDef: {
                getQuickFilterText: (
                  // eslint-disable-next-line @typescript-eslint/no-explicit-any
                  params: GetQuickFilterTextParams<any, any>
                ) => {
                  return params.column.getColId() == "display_name"
                    ? params.value
                    : "";
                },
              },
              quickFilterMatcher: (
                quickFilterParts: string[],
                rowQuickFilterAggregateText: string
              ) => {
                return (
                  rowQuickFilterAggregateText.indexOf(
                    quickFilterParts.join(" ")
                  ) >= 0
                );
              },
            }}
          >
            <DataGridQuickSearch
            // sx={{ width: "1.75rem" }}
            // label="Search by Field Name"
            ></DataGridQuickSearch>
            <DataGridActionAdd
              dialog={
                <DataDictionaryFieldFormDialog
                  selected_aggregation_level={
                    aggregationLevelFilter ? aggregationLevelFilter : "ISSU"
                  }
                ></DataDictionaryFieldFormDialog>
              }
              iconTooltipTitle="Add User-Defined Field"
              onUpdateUi={(gridMeta, agGridApi) => {
                setCurrentTab(DetailsTabs.Properties);
                const selectedNodes = agGridApi.getSelectedNodes();

                if (selectedNodes && selectedNodes[0]) {
                  const selectedNode = selectedNodes[0];

                  if (selectedNode.rowIndex) {
                    agGridApi.ensureIndexVisible(selectedNode.rowIndex);
                  }
                }
              }}
            ></DataGridActionAdd>
            <DataGridActionEdit
              dialog={
                <DataDictionaryFieldFormDialog></DataDictionaryFieldFormDialog>
              }
              onUpdateUi={refreshDataDictionaryField}
            ></DataGridActionEdit>
            <DataGridActionDelete
              operation={dataDictionarFieldsDeleteOperation}
              iconButtonProps={iconButtonProps}
              rowSelectionMode="multi"
            ></DataGridAction

