content.content:
import {
  FormLookupAutocomplete,
  getDialogResizePaperPropsSx,
} from "@solvasam/bizcomponents";
import {
  AsyncFormAutocomplete,
  AutocompleteDataServiceProviderDataSource,
  ColDefOverride,
  DataGridMeta,
  FormDataGrid,
  FormFieldGroup,
  FormTextField,
  FormValidateField,
  useField,
  useFormikContext,
} from "@textile/biz-components";
import {
  Alert,
  Button,
  DialogActions,
  DialogContent,
  Divider,
  IconButton,
  Stack,
  SxProps,
  TextFieldProps,
} from "@textile/mui";
import { Fragment, FunctionComponent, SyntheticEvent, useState } from "react";

import {
  DataDictionaryField,
  FieldDataType,
  MatrixValue,
} from "./data-dictionary.types";
import { LookupItem } from "../lookup-data/lookup-data.types";
import { baseUrl } from "../../apis";
import { TextCellEditor } from "@textile/ag-grid";
import { v4 as uuid } from "uuid";
import {
  AddIcon,
  DeleteIcon,
  Dialog,
  DialogTitle,
  PasteIcon,
} from "@textile/common";
import { Padding } from "@mui/icons-material";

const lookupDataSource: AutocompleteDataServiceProviderDataSource = {
  url: `${baseUrl}/lookupTypes`,
  dataPath: "lookup_types",
};

const dataTypeFieldProps: TextFieldProps = {
  label: "Data Type",
  variant: "outlined",
  required: true,
};
const lookupTextFieldProps: TextFieldProps = {
  label: "Lookup",
  variant: "outlined",
};

const gridSx: SxProps = { height: "250px", flexGrow: 1 };

const fieldGroupSx: SxProps = {
  pt: 1,
};

export const MatrixTables: FunctionComponent<{
  editMode?: boolean;
  initialData?: Partial<DataDictionaryField>;
}> = ({ editMode, initialData }) => {
  const [{ value: matrixColumns }, , { setValue: setMatrixColumns }] = useField<
    Partial<MatrixGridValue>[] | null
  >("table_fields[0].matrix_columns");
  const [{ value: matrixRows }, , { setValue: setMatrixRows }] = useField<
    Partial<MatrixGridValue>[] | null
  >("table_fields[1].matrix_rows");

  const [selectedColumns, setSelectedColumns] = useState<string[]>([]);
  const [selectedRows, setSelectedRows] = useState<string[]>([]);
  const [selectedType, setSelectedType] = useState<"Column" | "Row">("Column");
  const [openPasteDailog, setOpenPasteDailog] = useState<boolean>(false);
  const [disableColumnGridDelete, setDisableColumnGridDelete] =
    useState<boolean>(true);
  const [disableRowGridDelete, setDisableRowGridDelete] =
    useState<boolean>(true);

  const handleColumnsSelectionChange = (selectedRecord: MatrixGridValue[]) => {
    setSelectedColumns(
      selectedRecord.map((item) => {
        return item.id;
      })
    );
    if (editMode && selectedRecord.length > 0) {
      const isOldRecord =
        (initialData?.table_fields &&
          initialData?.table_fields.length > 0 &&
          initialData?.table_fields[0].matrix_columns &&
          (
            initialData?.table_fields[0].matrix_columns as MatrixGridValue[]
          ).some(
            (item) => selectedRecord.findIndex((sr) => sr.id === item.id) !== -1
          )) ||
        false;

      setDisableColumnGridDelete(isOldRecord);
    } else {
      setDisableColumnGridDelete(selectedRecord.length == 0);
    }
  };
  const handleMatrixColumnAdd = () => {
    setMatrixColumns([
      ...(matrixColumns ?? []),
      {
        id: uuid(),
        code: "",
        description: "",
      } as Partial<MatrixGridValue>,
    ]);
  };
  const handleMatrixColumnDelete = () => {
    if (selectedColumns.length > 0) {
      setMatrixColumns([
        ...(matrixColumns?.filter((item) => {
          return selectedColumns.indexOf(item.id ?? "") < 0;
        }) ?? []),
      ]);
    }
  };
  const handleMatrixColumnPasteClick = () => {
    setSelectedType("Column");
    setOpenPasteDailog(true);
  };

  const handleRowsSelectionChange = (selectedRecord: MatrixGridValue[]) => {
    setSelectedRows(
      selectedRecord.map((item) => {
        return item.id;
      })
    );
    if (editMode && selectedRecord.length > 0) {
      const isOldRecord =
        (initialData?.table_fields &&
          initialData?.table_fields.length > 0 &&
          initialData?.table_fields[1].matrix_rows &&
          (initialData?.table_fields[1].matrix_rows as MatrixGridValue[]).some(
            (item) => selectedRecord.findIndex((sr) => sr.id === item.id) !== -1
          )) ||
        false;
      setDisableRowGridDelete(isOldRecord);
    } else setDisableRowGridDelete(selectedRecord.length == 0);
  };
  const handleMatrixRowAdd = () => {
    setMatrixRows([
      ...(matrixRows ?? []),
      {
        id: uuid(),
        code: "",
        description: "",
      } as Partial<MatrixGridValue>,
    ]);
  };
  const handleMatrixRowDelete = () => {
    if (selectedRows.length > 0) {
      setMatrixRows([
        ...(matrixRows?.filter((item) => {
          return selectedRows.indexOf(item.id ?? "") < 0;
        }) ?? []),
      ]);
    }
  };
  const handleMatrixRowPasteClick = () => {
    setSelectedType("Row");
    setOpenPasteDailog(true);
  };

  return (
    <>
      <FormDataGrid
        fieldName="table_fields[0].matrix_columns"
        label="Matrix Columns"
        rowSelectionMode="multi"
        meta={matrixValuesMeta}
        colDefOverrides={colDefOverrides}
        sx={gridSx}
        onSelectionChanged={handleColumnsSelectionChange}
        agGridProps={{
          getRowHeight: () => 40,
          singleClickEdit: true,
          stopEditingWhenCellsLoseFocus: true,
        }}
      >
        <IconButton aria-label="Add" onClick={handleMatrixColumnAdd}>
          <AddIcon fontSize="large"></AddIcon>
        </IconButton>
        <IconButton aria-label="Paste" onClick={handleMatrixColumnPasteClick}>
          <PasteIcon size={24} />
        </IconButton>
        <IconButton
          aria-label="Delete"
          disabled={disableColumnGridDelete}
          onClick={handleMatrixColumnDelete}
        >
          <DeleteIcon />
        </IconButton>
      </FormDataGrid>

      <FormDataGrid
        fieldName="table_fields[1].matrix_rows"
        label="Matrix Rows"
        meta={matrixValuesMeta}
        colDefOverrides={colDefOverrides}
        sx={gridSx}
        rowSelectionMode="multi"
        onSelectionChanged={handleRowsSelectionChange}
        agGridProps={{
          getRowHeight: () => 40,
          singleClickEdit: true,
          stopEditingWhenCellsLoseFocus: true,
        }}
      >
        <IconButton aria-label="Add" onClick={handleMatrixRowAdd}>
          <AddIcon fontSize="large"></AddIcon>
        </IconButton>
        <IconButton aria-label="Paste" onClick={handleMatrixRowPasteClick}>
          <PasteIcon size={24} />
        </IconButton>
        <IconButton
          aria-label="Delete"
          disabled={disableRowGridDelete}
          onClick={handleMatrixRowDelete}
        >
          <DeleteIcon />
        </IconButton>
      </FormDataGrid>
      <ClipboardDataGrid
        openDialog={openPasteDailog}
        setOpenDialog={setOpenPasteDailog}
        type={selectedType}
        matrixColumns={matrixColumns}
        matrixRows={matrixRows}
      ></ClipboardDataGrid>
    </>
  );
};

const checkColumnsCompatibility = (rows: string[]) => {
  const gridFields = ["code", "description"];
  const currentline = rows[0].split("\t");
  return currentline.length === gridFields.length ? true : false;
};

interface MatrixGridValue extends MatrixValue {
  id: string;
}

const getMatrixGridData = (rows: string[]) => {
  const result: Partial<MatrixGridValue>[] = [];
  rows.forEach((row) => {
    const record: Partial<MatrixGridValue> = {};
    const matrixData = row.split("\t");
    record["code"] = matrixData[0];
    record["description"] = matrixData[1];
    result.push(record);
  });
  return result;
};

const ClipboardDataGrid: FunctionComponent<{
  openDialog: boolean;
  setOpenDialog: React.Dispatch<React.SetStateAction<boolean>>;
  type: string;
  matrixColumns?: Partial<MatrixGridValue>[] | null;
  matrixRows?: Partial<MatrixGridValue>[] | null;
}> = ({ openDialog, setOpenDialog, type, matrixColumns, matrixRows }) => {
  const { setFieldValue } = useFormikContext();
  const [invalidDataAlert, setInvalidDataAlert] = useState<boolean>(false);
  const [clipboardData, setClipboardData] = useState<MatrixGridValue[]>([]);

  const handleOnClose = () => {
    setFieldValue("matrix_paste_grid_data", undefined);
    setOpenDialog(false);
  };
  const handleOnSubmit = () => {
    if (type === "Column") {
      const updatedColumns = [...(matrixColumns ?? []), ...clipboardData];
      setFieldValue("table_fields[0].matrix_columns", updatedColumns);
    } else {
      const updatedRows = [...(matrixRows ?? []), ...clipboardData];
      setFieldValue("table_fields[1].matrix_rows", updatedRows);
    }
    setFieldValue("matrix_paste_grid_data", undefined);
    setOpenDialog(false);
  };

  return (
    <Dialog
      open={openDialog}
      fullWidth
      PaperProps={{ sx: getDialogResizePaperPropsSx("720px") }}
      draggable={true}
    >
      <DialogTitle>{`Paste Matrix ${type}s From Clip Board`}</DialogTitle>
      <DialogContent sx={{ p: 3 }}>
        <Fragment>
          <Alert sx={{ m: 2 }} variant="outlined" severity="info">
            Clipboard data must match the data format indicated below.
          </Alert>
          <FormDataGrid
            fieldName="matrix_paste_grid_data"
            meta={matrixValuesMeta}
            sx={gridSx}
          >
            <IconButton
              aria-label="paste"
              size="small"
              onClick={async () => {
                const data = await navigator.clipboard.readText();
                const clipboardRows = data.trim().split("\n");
                if (clipboardRows.length) {
                  if (checkColumnsCompatibility(clipboardRows)) {
                    setInvalidDataAlert(false);
                    const matrixGridClipBoardData =
                      getMatrixGridData(clipboardRows);
                    const rowData: MatrixGridValue[] =
                      matrixGridClipBoardData.map((row) => {
                        return {
                          id: uuid(),
                          code: row.code,
                          description: row.description,
                        } as MatrixGridValue;
                      });
                    setClipboardData(rowData);
                    setFieldValue("matrix_paste_grid_data", rowData);
                  } else {
                    setInvalidDataAlert(true);
                  }
                }
              }}
            >
              <PasteIcon size={24} />
