    },
  };
  const groupData = (groupings ?? [])
    .reduce<string[]>((types, grouping) => {
      return types.includes(grouping.group_by_type_code)
        ? types
        : [...types, grouping.group_by_type_code];
    }, [])
    .map((type) => {
      const formGroup: LookupItemFormGroupData = {
        lookupItemCodes: (groupings ?? [])
          .filter((group) => {
            return group.group_by_type_code === type;
          })
          .map((group) => {
            return group.group_by_item_code;
          }),
        lookupItemNames: [],
        lookupType: type,
      };

      return formGroup;
    });
  const groupingsFormData: LookupItemGroupingData = {
    group_by_names: groupData.length > 0 ? groupData : [defaultLookupItemGroup],
  };
  const handleBeforeSave = async (
    lookupGroupingsData: LookupItemGroupingData
  ) => {
    const lookupGroups = lookupGroupingsData.group_by_names
      .flatMap((lookupGroup) => {
        return lookupGroup.lookupItemNames;
