  method: "post",
  url: `${baseUrl}/payees:batchDelete`,
  operationConfirmedParamLocation: "body",
  idsField: "names",
};

export const PayeesScreen: FunctionComponent = () => {
  const [selectedPayeeId, setSelectedPayeeId] = useState<string | null>(null);
  const [selectedPayee, setSelectedPayee] = useState<Payee | null>(null);
  const { createAxiosInstance } = useAxiosFactory();
  const messageAnnouncer = useMessageAnnouncer();

  const handlePayeeSelectionChange = (selection: Payee[]) => {
    const [selectedPayee] = selection;

    setSelectedPayeeId(selectedPayee?.id ?? null);
  };

  useEffect(() => {
    const loadPayee = async () => {
      try {
        const axios = await createAxiosInstance();
        const { data } = await axios.get<Payee>(
          `${baseUrl}/payees/${selectedPayeeId}`
        );

        setSelectedPayee(data);
      } catch (error) {
        messageAnnouncer.error(`Failed: ${error}`);
      }
    };

    if (selectedPayeeId) {
      loadPayee();
    } else {
      setSelectedPayee(null);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [createAxiosInstance, selectedPayeeId]);

  const [refreshToken, refresh] = useRefreshToken();

  return (
    <Screen navigationId="solvasam-domaindata-ui-payees" sx={screenSx}>
      <ScreenHeader></ScreenHeader>
      <Stack direction="row" sx={payeesScreenContentContainerSx}>
        <Splitter expandable={true}>
          <AsyncDataGridPanel
            dataSource={payeesGridDataSource}
            rowSelectionMode="multi"
            onSelectionChanged={handlePayeeSelectionChange}
            sx={payeesGridSx}
            gridPersistOptions={{
              key: `dd-payees`,
              enabled: true,
            }}
          >
            <DataGridQuickSearch></DataGridQuickSearch>
            <DataGridActionAdd
              dialog={<PayeesFormDialog></PayeesFormDialog>}
            ></DataGridActionAdd>
            <DataGridActionEdit
              dialog={<PayeesFormDialog></PayeesFormDialog>}
              onUpdateUi={refresh}
            ></DataGridActionEdit>
            <DataGridActionDelete
              operation={payeesDeleteOperation}
              rowSelectionMode="multi"
            ></DataGridActionDelete>
            <DownloadActionMenu />
            <ActionMenu>
              <DataGridActionRefresh type="menuitem" icon={null} />
              <DataGridActionViewSource
                type="menuitem"
                datasource={payeesGridDataSource}
              ></DataGridActionViewSource>
            </ActionMenu>
          </AsyncDataGridPanel>
          {selectedPayee ? (
            <PayeeDetailsPanel
              payeeId={selectedPayee.id}
              sx={payeeDetailsSx}
              refreshToken={refreshToken}
            ></PayeeDetailsPanel>
          ) : null}
        </Splitter>
      </Stack>
    </Screen>
  );
};

