const tableTypeTextFieldProps: TextFieldProps = {
  label: "Table Type",
  variant: "outlined",
  required: true,
};

interface DataDictionaryTableFieldFormProps {
  editMode?: boolean;
  openDialog: boolean;
  setOpenTableTypeDialog: React.Dispatch<React.SetStateAction<boolean>>;
  initialData?: Partial<DataDictionaryField>;
}

interface TableTypeError {
  isError: boolean;
  message?: string;
}

const IsNullOrEmpty = (val: string) => {
  return val == null || val.trim() === "";
};
export const DataDictionaryTableFieldForm: FunctionComponent<
  DataDictionaryTableFieldFormProps
> = ({ editMode, openDialog, setOpenTableTypeDialog, initialData }) => {
  const [{ value: tableType }, , { setValue: setTableType }] =
    useField<TableType>("table_type");
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [{ value: tableFields }, , { setValue: setTableFields }] = useField<
    Partial<DataDictionaryFieldTableValue>[] | null
  >("table_fields");

  const { setFieldValue } = useFormikContext();

  useEffect(() => {
    if (editMode === false) {
      setTableType(TableType.ADJUSTMENTS);
    }
  }, []);

  useEffect(() => {
    if (editMode === false) {
      setTableFields(tableTypeMap[tableType]?.defaultValues ?? null);
    }
  }, [editMode, tableType]);
  const theme = useTheme();

  const defaultError: TableTypeError = { isError: false, message: "" };
  const [isgridEditable, setIsgridEditable] = useState<boolean>(false);
  const [gridError, setGridError] = useState<TableTypeError>(defaultError);
  const [matrixFieldError, setMatrixFieldError] =
    useState<TableTypeError>(defaultError);
  const [matrixGridError, setMatrixGridError] =
    useState<TableTypeError>(defaultError);

  useEffect(() => {
    setIsgridEditable(
      tableType !== TableType.ADJUSTMENTS &&
        tableType !== TableType.STRATIFICATION
    );
  }, [tableType]);
  const { dataTypeOptions, textTypeOptions } =
    useTableAutoCompleteOptions(openDialog);

  const colDefOverrides: ColDefOverride[] = [
    {
      field: "display_name",
      colDef: {
        editable: isgridEditable,
        cellEditor: TextCellEditor,
      },
    },
    {
      field: "data_type_description",
      colDef: {
        editable: isgridEditable,
        cellEditor: TextAutocompleteCellEditor,
        cellEditorParams: (params: any) => ({
          options: dataTypeOptions.filter(({ code }) => {
            return code !== "TABLE";
          }),
          value: params.data?.data_type,
        }),
        valueFormatter: (params: any) => {
          const option = dataTypeOptions.find(
            (item: CodePair) => item.code === params.value
          );
          return option ? option.description : params.value;
        },
        onCellValueChanged: (params: any) => {
          const selectedCode = params.newValue;
          const selectedOption = dataTypeOptions.find(
            (item: CodePair) => item.code === selectedCode
          );
          setFieldValue(
            "table_fields[" + params.node.rowIndex + "].data_type",
            selectedCode
          );
          setFieldValue(
            "table_fields[" + params.node.rowIndex + "].data_type_description",
            selectedOption ? selectedOption.description : ""
          );
          if (selectedCode !== "TEXT") {
            setFieldValue(
              "table_fields[" + params.node.rowIndex + "].lookup_type",
              null
            );
            setFieldValue(
              "table_fields[" +
                params.node.rowIndex +
                "].lookup_type_description",
              null
            );
          }
        },
      },
    },
    {
      field: "lookup_type_description",
      colDef: {
        cellEditorParams: (params: any) => ({
          options: textTypeOptions,
          value: params.data?.lookup_type,
        }),
        editable: (params: any) => {
          return isgridEditable && params.data.data_type === "TEXT";
        },
        cellEditor: TextAutocompleteCellEditor,
        valueFormatter: (params: any) => {
          const option = textTypeOptions.find(
            (item: CodePair) => item.code === params.value
          );
          return option ? option.description : params.value;
        },
        onCellValueChanged: (params: any) => {
          const selectedCode = params.newValue;
          const selectedOption = textTypeOptions.find(
            (item: CodePair) => item.code === selectedCode
          );
          setFieldValue(
            "table_fields[" + params.node.rowIndex + "].lookup_type",
            selectedCode
          );
          setFieldValue(
            "table_fields[" +
              params.node.rowIndex +
              "].lookup_type_description",
            selectedOption ? selectedOption.description : ""
          );
        },
      },
    },
  ];

  const [disableAdd, setDisableAdd] = useState<boolean>(false);
  const [disableDelete, setDisableDelete] = useState<boolean>(true);
  const [selectedTableFields, setSelectedTableFields] = useState<string[]>([]);

  const handleSelectionChange = (
    selectedRecord: DataDictionaryFieldTableValue[]
  ) => {
    if (isgridEditable) {
      setSelectedTableFields(
        selectedRecord.map((item) => {
          return item.id;
        })
      );
      if (editMode) {
        const isOldRecord =
          initialData?.table_fields?.some(
            (item) => selectedRecord.findIndex((sr) => sr.id === item.id) !== -1
          ) || false;

        setDisableDelete(isOldRecord);
      } else {
        setDisableDelete(selectedRecord.length == 0);
      }
    }
  };

  const handleOnClose = () => {
    //revert the table fields to old state and close wizard
    setTableFields(
      editMode
        ? (initialData?.table_fields as Partial<DataDictionaryFieldTableValue>[])
        : []
    );
    setTableType(
      editMode ? (initialData?.table_type as TableType) : TableType.ADJUSTMENTS
    );
    setOpenTableTypeDialog(false);
    setIsFullScreen(false);
  };

  const handleOnSubmit = () => {
    if (tableType == TableType.MATRIX && tableFields) {
      const matrixColumnField = tableFields.find(
        (x) => x.table_field_name === "field_column"
      );
      const matrixRowField = tableFields.find(
        (x) => x.table_field_name === "field_row"
      );
      if (
        !matrixColumnField?.matrix_columns ||
        matrixColumnField.matrix_columns.length === 0 ||
        !matrixRowField?.matrix_rows ||
        matrixRowField.matrix_rows.length === 0
      ) {
        setMatrixGridError({
          isError: true,
          message: "You must have one or more values for both columns and rows",
        });
        return false;
      } else if (
        matrixColumnField.matrix_columns.length !==
          new Set(matrixColumnField.matrix_columns.map((item) => item.code))
            .size ||
        matrixRowField.matrix_rows.length !==
          new Set(matrixRowField.matrix_rows.map((item) => item.code)).size
      ) {
        setMatrixGridError({
          isError: true,
          message: "Values of code column must be unique",
        });
        return false;
      }
    } else if (
      tableFields &&
      tableFields?.some((item) => {
        return (
          IsNullOrEmpty(item.display_name ?? "") ||
          IsNullOrEmpty(item.data_type_description ?? "")
        );
      })
    ) {
      setGridError({
        isError: true,
        message: "Display Name and Data Type Fields are required",
      });
      return false;
    }
    setOpenTableTypeDialog(false);
  };

  c

